/**
 * ShopNav 新老导航栏切换开关
 *
 * 通过全局 window.__downgradedConfiguration.disableNewShopNav 控制：
 * - undefined / 任意非 'true' 值 → 使用新导航栏 (Navigation 组件)
 * - 'true' → 降级到老导航栏 (原 fixed header 实现)
 *
 * 默认启用新导航栏。当新导航出现问题时通过下发 'true' 降级。
 */
export const isNewShopNavEnabled = (): boolean => {
  return (window?.__downgradedConfiguration as any)?.disableNewShopNav !== 'true';
};

