import { Navigator } from '@ali/uni-api';
import React, { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { useDispatch, useGlobalState } from '@ali/et-context';
import styles from './index.module.css';
import { Navigation } from '@ali/acom-unify-mobile-components';
import { showMenu } from '@/hooks/globalMenuAction';
import { isNewShopNavEnabled } from './utils/featureSwitch';

// 导入类型定义
import type { CouponPopupInfo, ShopNavData, ToolbarFields } from './types';

// 导入子组件
import SearchSection from './components/SearchSection';
import RedEnvelopeSection from './components/RedEnvelopeSection';
import FavoriteSection from './components/FavoriteSection';
import ImSection from './components/ImSection';
import CouponPopup from './components/CouponPopup';
import DeliveryBusinessNavbar from './components/DeliveryBusinessNavbar';

// 导入自定义Hooks
import { useNavbarPosition } from './hooks/useNavbarPosition';
import { useBusinessNavigate } from '@/hooks/useBusinessNavigate';
import {
  notifyFirstScreenScrolled,
  recordFirstScreenMenuExpose,
} from '@/hooks/useFirstScreenMonitor';

// 导入工具函数
import { createSearchClickHandler } from './utils/utils';
import {
  adaptDeliveryBusinessInfo,
  calculateNavbarDeliveryOpacity,
  shouldShowNavbarDeliveryBusiness,
} from './utils/dataAdapter';
import platform from '@/common/et-arsenal/utils/platform';

const ShopNav: React.FC = () => {
  // 全局状态
  const data = useGlobalState(
    (state) => state?.headData?.data?.wm_store_header_toolbar,
  ) as ShopNavData;

  // 获取自取功能数据 - 从toolbar数据中获取并适配
  const deliveryBusinessInfo = adaptDeliveryBusinessInfo(data?.fields?.deliveryBusinessInfo);
  const globalConfig = useGlobalState((state) => state?.globalConfig);
  const dispatch = useDispatch();

  // 导航Hook
  const { navigateToShopSearch } = useBusinessNavigate();

  const fields = data?.fields ?? {};
  const { search, favored, redEnvelope, storeIm, storeDecoType } = fields;

  // 新老导航切换开关 (在 hooks 之前调用,确保 hooks 顺序稳定)
  const useNewNav = useMemo(() => isNewShopNavEnabled(), []);

  // 使用自定义Hooks (老版本依赖 navLeftMargin/navRightMargin)
  const { navLeftMargin, navRightMargin, screenInfo } = useNavbarPosition();
  const { statusBarHeight, navBarHeight } = screenInfo;

  const isSingleShop = storeDecoType === 1;

  // 内部状态管理
  const [opacity, setOpacity] = useState(isSingleShop ? 1 : 0);
  const [searchExplandOpacity, setSearchExplandOpacity] = useState(isSingleShop ? 1 : 0);
  const [searchIconOpacity, setSearchIconOpacity] = useState(isSingleShop ? 1 : 0);
  const [searchTransform, setSearchTransform] = useState(0);
  const [transitionHeight, setTransitionHeight] = useState(100);

  // 获取店招类型(用于计算 transitionHeight)
  const headData = useGlobalState((state) => state?.headData);
  const posterHead = headData?.data?.wm_store_header_info?.fields?.posterHead;
  const isHighStyle = Boolean(posterHead?.videoCoverPicUrl || posterHead?.brandStorePoster);

  // IM 按钮显示条件：storeIm 字段不为空
  const showIM = storeIm && Object.keys(storeIm).length > 0;

  // 收藏弹框相关状态
  const [showCouponPopup, setShowCouponPopup] = useState(false);
  const [couponPopupInfo, setCouponPopupInfo] = useState<CouponPopupInfo | null>(null);

  // Refs
  const etTopRef = useRef<HTMLDivElement>(null);
  const rafRef = useRef<number>();
  const lastScrollTop = useRef(0);
  const isSearchExpanded = useRef(false);

  const [tabTop] = useState(navBarHeight);

  // 红包相关状态计算
  const redEnvelopeCountDownShow = useMemo(() => {
    if (!redEnvelope || redEnvelope.couponType !== 7) return false;
    if (!redEnvelope.countDown) return false;
    if (typeof redEnvelope.countDown !== 'number') return false;
    return redEnvelope.countDown < 60 * 60;
  }, [redEnvelope]);

  const redEnvelopeWhiteButtonShow = useMemo(
    () => redEnvelopeCountDownShow,
    [redEnvelopeCountDownShow],
  );

  // 透明度更新逻辑
  const updateOpacity = useCallback(
    (scrollTop: number) => {
      if (scrollTop < 0) {
        scrollTop = 0;
      }
      if (scrollTop > tabTop) {
        scrollTop = tabTop;
      }
      const scroll = scrollTop / tabTop;
      const rateNum = Number(scroll.toFixed(2));
      // 兜底透明度变化不及时
      const newOpacity = rateNum > 0.8 ? 1 : rateNum < 0.3 ? 0 : rateNum;

      if (Math.abs(newOpacity - opacity) > 0.01) {
        setOpacity(newOpacity);

        // 更新导航栏主题色
        if (newOpacity > 0.5) {
          $ele().utils.navbar.setTheme({ theme: 'LIGHT' });
        } else {
          $ele().utils.navbar.setTheme({ theme: 'DARK' });
        }

        // 更新搜索栏的展开状态 - 关键：检查isSearchExpanded状态
        if (!isSearchExpanded.current) {
          setSearchExplandOpacity(newOpacity);
          setSearchIconOpacity(newOpacity);

          // 根据红包按钮状态调整搜索框的移动距离
          const moveDistance = redEnvelopeWhiteButtonShow ? -44 : -72;
          setSearchTransform(newOpacity * moveDistance);
        }
      }
    },
    [tabTop, opacity, redEnvelopeWhiteButtonShow],
  );

  // 滚动处理函数
  const handleScroll = useCallback(
    (e: any) => {
      if (rafRef.current) {
        cancelAnimationFrame(rafRef.current);
      }

      // rafRef.current = requestAnimationFrame(() => {
      let scrollTop = 0;

      // 优先从事件对象的 contentOffset.y 获取 scrollTop
      if (e?.detail?.contentOffset?.y !== undefined) {
        scrollTop = -e.detail.contentOffset.y;
      } else {
        // 降级方案：从 document 获取
        // @ts-ignore
        // eslint-disable-next-line no-restricted-properties
        // #ifdef miniapp
        scrollTop = e?.target?.scrollTop || 0;
        // #endif
        // #ifndef miniapp
        scrollTop = document.documentElement.scrollTop || 0;
        // #endif
      }

      if (Math.abs(scrollTop - lastScrollTop.current) > 5) {
        lastScrollTop.current = scrollTop;
        updateOpacity(scrollTop);
      }
      notifyFirstScreenScrolled();
      // });
    },
    [updateOpacity],
  );

  // 事件处理函数
  const onSearchClick = useMemo(
    () => createSearchClickHandler(search, globalConfig, navigateToShopSearch),
    [search, globalConfig, navigateToShopSearch],
  );

  const handleCloseCouponPopup = useCallback(() => {
    setShowCouponPopup(false);
    setCouponPopupInfo(null);
  }, []);

  const handleCouponPopupAddCart = useCallback(() => {
    // // // console.log('处理加购逻辑');
    // TODO: 实现加入购物车逻辑
    handleCloseCouponPopup();
  }, [handleCloseCouponPopup]);

  const handleDefaultRedEnvelopeClick = useCallback(() => {
    $ele().ltracker.click('compositive_discount.1', {
      restaurant_id: globalConfig?.encryptStoreId,
      type: redEnvelope?.text && redEnvelope?.text?.length > 0 ? 2 : 1,
    });
    dispatch({ type: 'page/setShowPromotionPopup', payload: true });
  }, [dispatch, globalConfig?.encryptStoreId, redEnvelope?.text]);

  const handleScrollRedEnvelopeClick = useCallback(() => {
    if (opacity < 0.1) {
      $ele().ltracker.click('search.1', search?.userTrack?.bizParams ?? {});
      onSearchClick('icon');
      return;
    }
    $ele().ltracker.click('compositive_discount.1', {
      restaurant_id: globalConfig?.encryptStoreId,
      type: redEnvelope?.text && redEnvelope?.text?.length > 0 ? 2 : 1,
    });
    dispatch({ type: 'page/setShowPromotionPopup', payload: true });
  }, [
    opacity,
    onSearchClick,
    dispatch,
    globalConfig?.encryptStoreId,
    redEnvelope?.text,
    search?.userTrack,
  ]);

  // 返回处理函数(所有环境统一)
  const onBack = useCallback(() => {
    // #ifdef miniapp
    my?.navigateBack();
    // #endif
    // #ifndef miniapp
    Navigator.close({});
    // #endif
  }, []);

  // Navigation 的 ... (more) 按钮点击 - 桥接到原有 GlobalMenu 分享/举报菜单
  // 等价于原 native 菜单按钮被点击 → showETGlobalMenu 注册的拦截回调 → showMenu(response)
  const handleShare = useCallback(() => {
    $ele().ltracker.click('shopnav.share', {
      restaurant_id: globalConfig?.encryptStoreId,
    });
    if (headData) {
      showMenu(headData);
    }
  }, [globalConfig?.encryptStoreId, headData]);

  // 计算 transitionHeight (店招高度 - 导航栏高度)
  useEffect(() => {
    const html = document.documentElement;
    const clientWidth = Math.round(html.clientWidth || window.innerWidth);
    // 店铺店招高度约为 38.4vw (标准) 或 56vw (high style)
    const posterHeight = isHighStyle ? 56 * clientWidth / 100 : 38.4 * clientWidth / 100;
    const navHeight = statusBarHeight + 44;
    setTransitionHeight(Math.max(0, posterHeight - navHeight));
  }, [isHighStyle, statusBarHeight]);

  // 初始化效果
  useEffect(() => {
    // $ele().utils.navbar.setImmersive({ immersive: true });
    // $ele().utils.navbar.setTheme({ theme: 'DARK' });
  }, []);

  useEffect(() => {
    const handler = () => {
      updateOpacity(tabTop);
    };
    $ele().utils.eventEmitter.on('menuWillAnchor', handler);
    return () => {
      $ele().utils.eventEmitter.off('menuWillAnchor', handler);
    };
  }, [tabTop, updateOpacity]);

  useEffect(() => {
    setOpacity(isSingleShop ? 1 : 0);
    setSearchExplandOpacity(isSingleShop ? 1 : 0);
    setSearchIconOpacity(isSingleShop ? 1 : 0);
  }, [isSingleShop]);

  // 监听滚动事件
  useEffect(() => {
    // 极简店铺不监听滚动事件
    if (isSingleShop) {
      // setTheme 内部已处理预热逻辑
      $ele().utils.navbar.setTheme({ theme: 'LIGHT' });
      return;
    }
    // @ts-ignore
    // eslint-disable-next-line no-restricted-properties
    const $list = document.getElementById('et-store-list');
    let useComponentListener = $ele().utils.platform.isEA || $ele().utils.isWeex;
    console.log('[ShopNav] useComponentListener', useComponentListener);
    if ($list && useComponentListener) {
      $list.addEventListener('scroll', handleScroll);
    } else {
      // @ts-ignore
      window.addEventListener('scroll', handleScroll, { passive: true });
    }

    return () => {
      // @ts-ignore
      if ($list && useComponentListener) {
        $list.removeEventListener('scroll', handleScroll);
      } else {
        // @ts-ignore
        window.removeEventListener('scroll', handleScroll);
      }
      if (rafRef.current) {
        cancelAnimationFrame(rafRef.current);
      }
    };
  }, [handleScroll, isSingleShop]);

  useEffect(() => {
    // 初始化导航栏颜色
    // 更新导航栏主题色
    if (opacity > 0.5) {
      $ele().utils.navbar.setTheme({ theme: 'LIGHT' });
    } else {
      $ele().utils.navbar.setTheme({ theme: 'DARK' });
    }
  }, []);

  // 如果没有有效数据，不显示组件
  if (!fields) {
    return null;
  }

  const hasDeliveryBusiness = shouldShowNavbarDeliveryBusiness(deliveryBusinessInfo);

  // 复用的右侧按钮组 (新老导航共用)
  const renderRightSection = () => (
    <>
      {/* 搜索区域 */}
      {search && (
        <SearchSection
          search={search}
          storeDecoType={storeDecoType}
          searchExplandOpacity={searchExplandOpacity}
          searchIconOpacity={searchIconOpacity}
          searchTransform={searchTransform}
          redEnvelope={redEnvelope}
          redEnvelopeWhiteButtonShow={redEnvelopeWhiteButtonShow}
          hasDeliveryBusiness={hasDeliveryBusiness}
          opacity={opacity}
          onSearchClick={onSearchClick}
        />
      )}

      {/* 红包区域 */}
      {redEnvelope && (
        <RedEnvelopeSection
          redEnvelope={redEnvelope}
          opacity={opacity}
          searchExplandOpacity={searchExplandOpacity}
          redEnvelopeCountDownShow={redEnvelopeCountDownShow}
          redEnvelopeWhiteButtonShow={redEnvelopeWhiteButtonShow}
          onDefaultClick={handleDefaultRedEnvelopeClick}
          onScrollClick={handleScrollRedEnvelopeClick}
        />
      )}

      {/* IM 客服区域 */}
      {showIM && storeIm && (
        <ImSection storeIm={storeIm} opacity={opacity} storeDecoType={storeDecoType} />
      )}

      {/* 收藏区域 */}
      {favored && (
        <FavoriteSection
          favored={favored}
          opacity={opacity}
          storeDecoType={storeDecoType}
          redEnvelope={redEnvelope}
          redEnvelopeCountDownShow={redEnvelopeCountDownShow}
          shopId={globalConfig?.encryptStoreId}
          setShowCouponPopup={setShowCouponPopup}
          setCouponPopupInfo={setCouponPopupInfo}
        />
      )}
    </>
  );

  return (
    <>
      {useNewNav ? (
        <Navigation
          mode={opacity > 0.5 ? 'light' : 'dark'}
          title={
            <div style={{ display: 'flex', alignItems: 'center', width: '100%', height: '44px', overflow: 'visible' }}>
              {/* DeliveryBusinessNavbar: 始终显示在左侧 */}
              {hasDeliveryBusiness && (
                <div style={{ marginRight: 'auto' }}>
                  <DeliveryBusinessNavbar
                    deliveryBusinessInfo={deliveryBusinessInfo ?? undefined}
                    currentBusinessType={deliveryBusinessInfo?.businessType}
                    onBusinessTypeChange={(businessType) => {
                      // TODO: 实现业务类型切换逻辑
                    }}
                    isVisible={true}
                    opacity={calculateNavbarDeliveryOpacity(deliveryBusinessInfo, opacity)}
                    backgroundType={opacity > 0.5 ? 'gray' : 'transparent'}
                  />
                </div>
              )}

              {/* 右侧按钮组 */}
              <div style={{ display: 'flex', alignItems: 'center', marginLeft: hasDeliveryBusiness ? '0' : 'auto' }}>
                {renderRightSection()}
              </div>
            </div>
          }
          onClickBack={onBack}
          onClickMore={handleShare}
          // #ifdef miniapp
          style={{
            padding: `${statusBarHeight}px 10px 0`,
            height: `${statusBarHeight + 44}px`,
          }}
          // #endif
          transitionConfig={{
            open: true,
            targetColor: '#ffffff',
            targetMode: 'light',
            transitionHeight: transitionHeight,
          }}
        />
      ) : (
        // 老版本导航栏 (与原 master_ea 完全一致)
        <header
          className={styles.shop__nav}
          ref={etTopRef}
          style={{
            backgroundColor: `rgba(255,255,255,${opacity})`,
            willChange: 'opacity, background-color',
            transform: 'translateZ(0)',
            height: `${navBarHeight}px`,
            paddingTop: `${statusBarHeight}px`,
          }}
        >
          <div className={styles.nav__bar}>
            {$ele().utils.navbar.isShowNavBarBackButton() && typeof my === 'undefined' && (
              <div
                className={styles.clickArea}
                onClick={() => Navigator.close({})}
                style={{
                  filter: opacity > 0.5 ? 'brightness(0)' : 'none',
                  transition: 'filter 0.3s',
                }}
                role="button"
                aria-label="返回"
                tabIndex={0}
              />
            )}

            {/* 自取功能区域 - 移到最左边（返回按钮右侧） */}
            {hasDeliveryBusiness && (
              <div style={{ marginLeft: '48px', marginRight: 'auto' }}>
                <DeliveryBusinessNavbar
                  deliveryBusinessInfo={deliveryBusinessInfo ?? undefined}
                  currentBusinessType={deliveryBusinessInfo?.businessType}
                  onBusinessTypeChange={(businessType) => {
                    // TODO: 实现业务类型切换逻辑
                  }}
                  isVisible={true}
                  opacity={calculateNavbarDeliveryOpacity(deliveryBusinessInfo, opacity)}
                  backgroundType={opacity > 0.5 ? 'gray' : 'transparent'}
                />
              </div>
            )}

            <div
              className={styles.nav__right}
              style={{
                marginLeft: hasDeliveryBusiness ? '0' : navLeftMargin, // 有自取功能时不需要左边距
                marginRight: navRightMargin,
              }}
            >
              {renderRightSection()}
            </div>
          </div>
        </header>
      )}

      {/* 收藏弹框 */}
      <CouponPopup
        visible={showCouponPopup}
        couponPopupInfo={couponPopupInfo}
        onClose={handleCloseCouponPopup}
        onAddCart={handleCouponPopupAddCart}
      />
    </>
  );
};
export default ShopNav;

