      dispatch({
        type: 'page/error',
        payload: new ConchShopIdError({
          message: '店铺 ID 已过期',
        }),
      });
      return;
    }

    if (urlParams?.brandId && !urlParams?.shopId) {
      const shopId = await getShopIdWithBrandId(urlParams?.brandId, 0);
      if (!shopId) {
        dispatch({
          type: 'page/error',
          payload: new ConchShopIdError({
            message: '店铺 ID 已过期',
          }),
