      try {
        const storeTransmitObject = JSON.parse(urlParams.storeTransmit);
        if (storeTransmitObject.psc && storeTransmitObject.psc !== '') {
          triggerPageStabilityTag('psc', storeTransmitObject.psc);
        }
        // 搜推售卡进店需求，新增进店啦浮层需求，如果是1强制啦浮层
        if (storeTransmitObject?.actionType === '1') {
          setTimeout(() => {
            const anchorBlockCode = storeTransmitObject?.anchorBlockCode ?? '';
