      try {
        const shopId = urlParams.shopId ?? '';
        if (shopId) {
          // 进店时默认回到第一个分栏，sn=1，totalSn暂时设为0（会在菜单数据加载后更新）
          SecurityReportService.reportStoreEntry(shopId, 1, 0);
        }
      } catch (error) {
        console.error('[Home] 进店安全上报失败:', error);
      }
    });

