        },
        {},
      );
    } catch (e) {
      console.error('静默登录失败', e);
    }

    // #ifndef miniapp
    if (typeof document !== 'undefined' && typeof window !== 'undefined') {
      interface MemoryWarningEvent {
        level?: string;
      }
      const memoryWarningHandler = (event: MemoryWarningEvent): void => {
        // // // // console.log('[memory]', event);
        const currentPath = typeof window !== 'undefined' ? window.location.pathname : 'unknown';
        const currentActionData = EtGlobalData.get('currentAction');
        const currentAction =
          (typeof currentActionData === 'string'
            ? currentActionData
            : String(currentActionData || '')) || 'unknown';
        $ele().answer.logCount({
