      if (!(window as any).__etMemoryWarningListenerAttached) {
        document.addEventListener('memorywarning', memoryWarningHandler as EventListener);
        (window as any).__etMemoryWarningListenerAttached = true;
      }
    }

    // #endif

    /* 增加几个全局的事件监听，方便跨组件触发 */
