  // 🆕 重构：全量刷新处理函数
  const handleFullRefresh = useCallback(
    async (state: any, refreshTag?: string) => {
      // #ifndef miniapp
      EtGlobalData.set('currentAction', 'pageRefresh'); // 页面刷新
      // #endif
      const { urlParams, businessType, cartsToShopPromotionParam } = state;
      const requestData = await getShopRequestData(
        urlParams,
        businessType,
        refreshTag,
        cartsToShopPromotionParam,
      );

      // 先发篮子接口，否则会串行请求body+篮子
      $ele().utils.eventEmitter.emit('cartRequest', { restaurant_id: urlParams.shopId });

      const [headResult, menuResult, sceneResult] = await Promise.allSettled([
        getStoreHead(requestData),
        getStoreMenu(requestData),
        getStoreScene(requestData),
      ]);

      if (headResult.status !== 'fulfilled') {
        setState({
          headData: { error: headResult.reason, dataToken: 'empty' },
          pageLoading: false,
        });
      } else if (menuResult.status !== 'fulfilled') {
        setState({
          menuData: { error: menuResult.reason, dataToken: 'empty' },
          pageLoading: false,
        });
      } else {
        const dataToken = headResult.value?.dataToken ?? 'empty';
        const globalConfig = headResult.value?.extra?.globalConfig ?? {};
        const storeTheme = getThemeConfig(globalConfig.theme ?? {}, globalConfig?.brandId, true);

        // 🆕 从 menuResult 中提取并存储 tppTraceId
        const menuGlobalConfig = menuResult.value?.extra?.globalConfig ?? {};
        const tppTraceId = menuGlobalConfig?.tppTraceId;
        if (tppTraceId) {
          const shopId = globalConfig?.encryptStoreId || urlParams.shopId;
          // 存储到全局埋点
          try {
            $ele().ltracker.setBaseInfo({
              exParams: {
                tppTraceId,
              },
            });
          } catch (error) {
            console.warn('[店铺刷新] 设置 tppTraceId 到埋点失败:', error);
          }

          // 存储到 MEMKVStorage，供商详消费
          // #ifndef miniapp
          try {
            MEMKVStorage.setItem({
              key: `${shopId}_tppTraceId`,
              value: tppTraceId,
            });
          } catch (error) {
            console.warn('[店铺刷新] 存储 tppTraceId 到 MEMKVStorage 失败:', error);
          }
          // #endif
        }

        // 新人专享数据为空
        const empty =
          sceneResult.status !== 'fulfilled' ||
          !sceneResult?.value ||
          !sceneResult?.value?.data?.resultMap?.shopSceneTabNewer?.tabs?.[0];

        const refreshStoreTabList =
          headResult.value?.data?.wm_store_header_tabbar?.fields?.items?.filter(
            (item: TabBarItem) =>
              item.fields.type === '0'
                ? item.fields.key === 'newer_scene'
                  ? !empty
                  : true
                : false,
          );
        const menuIndex = refreshStoreTabList?.findIndex(
          (item: TabBarItem) => item.fields.key === 'menu_page',
        );
        const tbSellerId =
          headResult.value?.data?.wm_store_header_info?.fields?.storeInfo?.sellerId;
        const tbStoreId =
          headResult.value?.data?.wm_store_header_info?.fields?.storeInfo?.tbStoreId;
        const shopId = globalConfig?.encryptStoreId || urlParams.shopId;
        const errorInfo = headResult.value?.error || menuResult.value?.error;
        const localErrorInstance = errorInfo
          ? createErrorInstance(errorInfo, '店铺数据刷新失败')
          : undefined;
        setState(
          {
            headData: headResult.value,
            menuData: menuResult.value,
            sceneData: empty ? null : sceneResult.value,
            shopId,
            tbSellerId,
            tbStoreId,
            menuIndex,
            tabIndex: 0,
            showFooter: true,
            urlParams: {
              ...urlParams,
              shopId,
            }, // 重写下shopId，店铺id置换逻辑
            storeTheme,
            globalConfig,
            storeTabList: refreshStoreTabList,
            errorInstance: localErrorInstance,
            dataToken,
            pageLoading: false,
            refreshingTime: Date.now(),
          },
          'UPDATE_MENU',
          true,
        );

        setTimeout(() => {
          // eslint-disable-next-line no-restricted-properties
          const slider = document.getElementById('store-slider') as any;
          slider?.slideTo?.(0, false);
        }, 50);

        // 存储数据到缓存
        if (headResult.value && !headResult.value.error) {
          setHeadCache(shopId, headResult.value);
        }
        if (menuResult.value && !menuResult.value.error) {
          setBodyCache(shopId, menuResult.value);
        }
      }
    },
    [setState],
  );

  // 🆕 修改：主 refresh action，根据 payload 类型分发到不同的子 action
  useRegisterAction(
    'page/refresh',
    useCallback(
      async (state, payload?: RefreshPayload) => {
        // 判断当前页面是否可见
        const currentUrl = typeof window !== 'undefined' ? window.location.href : '';
        const targetPath = '/app/TBTakeout/et-store/home';
        const isPageVisible = currentUrl.includes(targetPath);

        // 🆕 新增：解析 payload 参数
        if (!payload || typeof payload === 'boolean') {
          // 兼容现有逻辑：boolean 值表示是否显示 loading 的全量刷新
          const shouldShowLoading = payload;

          if (shouldShowLoading && isPageVisible) {
            showLoading();
          }

          try {
            // // // console.log('page/refresh');
            // 保持现有的全量刷新逻辑（reloadShop）
            await handleFullRefresh(state);
            hideLoading();
          } catch (error) {
            hideLoading();
            console.error('页面刷新失败:', error);
          }
        } else if (typeof payload === 'object' && payload != null) {
          // 🆕 新逻辑：从 map 中读取字段
          const { type, refreshTag } = payload;
          try {
            switch (type) {
              case 'reloadHeader':
                // 调用 header 刷新 action
                console.info('店铺头部刷新', refreshTag);
                await dispatch({ type: 'page/refreshHeader', payload: refreshTag });
                break;

              case 'reloadBody':
                // 调用 body 刷新 action
                console.info('店铺body刷新', refreshTag);
                await dispatch({ type: 'page/refreshBody', payload: refreshTag });
                break;

              case 'reloadShop':
              default:
                // 全量刷新，与现有逻辑保持一致
                if (payload?.showLoading && isPageVisible) {
                  showLoading();
                }
                console.info('店铺全量刷新', refreshTag);
                await handleFullRefresh(state, refreshTag);
                break;
            }
            hideLoading();
          } catch (error) {
            hideLoading();
            console.error('页面刷新失败:', error);
          }
        }
      },
      [dispatch, handleFullRefresh],
    ),
  );

