          dispatch({
            type: 'page/changeTab',
            payload: {
              tabIndex: state.menuIndex ?? 0,
              switchType: 'scroll',
            },
          });
          // eslint-disable-next-line no-restricted-properties
          const slider = document.getElementById('store-slider') as any;
          slider?.slideTo?.(state.menuIndex ?? 0, false);
          setTimeout(() => {
            dispatch({
              type: 'page/menuAnchor',
              payload,
            });
          }, 300);
        } else {
          const menuAnchor: AnchorTo = state.menuAnchor;
          if (menuAnchor && payload) {
            menuAnchor(payload);
          }
        }
      },
      [dispatch],
    ),
  );

  // 打开提醒
  const handleSetShowPromotionPopup = useCallback(
    async (state, payload) => {
      setState({ showPromotionPopup: payload });
    },
    [setState],
  );

  useRegisterAction('page/setShowPromotionPopup', handleSetShowPromotionPopup);

  // 天降弹窗
  const handleSetShowSkyFallPopup = useCallback(
    async (state, payload) => {
      setState({ showSkyFallPopup: payload });
    },
    [setState],
  );

  useRegisterAction('page/setShowSkyFallPopup', handleSetShowSkyFallPopup);

  /**
   * 预加载搭售无码浮层
   */
  setTimeout(() => {
    prefetch([{ cardId: payToBuyVipCardId, cardPlanId: payToBuyPlanVipId }], {
      cacheType: 'hybrid',
    });
    prefetch([{ cardId: payToBuyCardId, cardPlanId: payToBuyPlanId }], { cacheType: 'hybrid' });
  }, 3000);

  // 设置预定时间
  useRegisterAction(
    'page/setBookingTime',
    useCallback(
      async (state, payload) => {
        // 设置到全局状态
        setState({
          bookingData: { ...payload },
        });

        // 同时写入到 window.__GLOBAL_STATE__
        if (!window.__GLOBAL_STATE__) {
          window.__GLOBAL_STATE__ = {};
        }
        window.__GLOBAL_STATE__.bookTime = payload.bookTime || '';
        window.__GLOBAL_STATE__.deliveryTime = payload.deliveryTime || '';

        dispatch({ type: 'page/refresh', payload: true });
      },
      [setState, dispatch],
    ),
  );

  // 打开预订时间面板
  const handleShowBookingPanel = useCallback(
    async (state, payload) => {
      setState({ showBookingPannel: payload });
    },
    [setState],
  );

  useRegisterAction('page/showBookingPanel', handleShowBookingPanel);

  // 设置 BusinessType
  useRegisterAction(
    'page/setBusinessType',
    useCallback(
      async (state, businessType) => {
        const pvParams = {
          businessType,
        };
        $ele()?.ltracker?.setBaseInfo({
          exParams: pvParams,
        });
        // 设置到全局状态
        setState({
          businessType,
        });
        await $ele().storage.setItem('businessType', businessType, 'page');
        // 兼容二级页取值,$ele上的kv无法自定义
        setNextValue('businessType', businessType);

        EtGlobalData.set('user_switched_delivery_mode', {
          businessType,
          timestamp: Date.now(),
        });
        // 再兼容下回流app后状态带到二级页
        // #ifndef miniapp
        if (platform.isEleme) {
          try {
            LMageX.addGlobalData({
              key: WEEX_SHOP_BUSINESS_TYPE_KEY,
              value: String(businessType ?? '0'),
            });
          } catch (error) {}
        }
        // #endif
        if (!window.__GLOBAL_STATE__) {
          window.__GLOBAL_STATE__ = {};
        }
        window.__GLOBAL_STATE__.businessType = businessType || '0';

        dispatch({ type: 'page/refresh', payload: true });
      },
      [setState, dispatch],
    ),
  );

  // 设置 tabbar 吸顶状态
  const handleSetTabbarStickyState = useCallback(
    async (state, stickyState) => {
      // 设置到全局状态
      setState({
        tabbarStickyState: stickyState,
      });

      if (stickyState) {
        const autoScroll = Boolean((window as any).autoAnchor);
        recordFirstScreenMenuExpose({ autoScroll });
      }
    },
    [setState],
  );

  useRegisterAction('page/setTabbarStickyState', handleSetTabbarStickyState);

  const handleSetNeedRefreshOnShow = useCallback(
    async (state, payload) => {
      const { needRefreshOnShow: shouldRefreshOnShow, needLoading: shouldShowLoading = false } =
        payload ?? {};
      setState({
        needRefreshOnShow: shouldRefreshOnShow,
        needLoading: shouldShowLoading,
      });
    },
    [setState],
  );

  useRegisterAction('page/setNeedRefreshOnShow', handleSetNeedRefreshOnShow);

  // 触发拼单校验

  const handlePindanCheck = useCallback(
    async (state) => {
      const { urlParams, businessType } = state;
      const isFromPindan = urlParams.source === 'pindan' || urlParams.source === 'pindan_new';
      const isBusinessType1 = businessType === 1 || businessType === '1';
      if (!isFromPindan && !isBusinessType1) {
        getStorePindan()
          .then((response) => {
            const { data } = response;
            if (data) {
              setState({ pindanEntrance: data });
            }
          })
          .catch(() => {});
      }
    },
    [setState],
  );

  useRegisterAction('page/pindanCheck', handlePindanCheck);

  // 页面可行性变化
  usePageOnShow(
    useCallback(() => {
      // 防止重复执行
      if (onShowExecutedRef.current) {
        return;
      }
      let cartReqNum = 0;
      onShowExecutedRef.current = true;

      const deliveryModeData = EtGlobalData.get('user_switched_delivery_mode');

      if (deliveryModeData?.businessType !== undefined && deliveryModeData?.timestamp) {
        // 检查时间戳是否在5分钟内
        const now = Date.now();
        const fiveMinutes = 5 * 60 * 1000; // 5分钟
        const isWithinTimeLimit = now - deliveryModeData.timestamp < fiveMinutes;

        // 只有当新的 businessType 与当前不同时才触发刷新
        if (isWithinTimeLimit && deliveryModeData.businessType !== currentBusinessType) {
          cartReqNum++;
          dispatch({
            type: 'page/setBusinessType',
            payload: deliveryModeData?.businessType,
          });
        }
      }

      if (needRefreshOnShow) {
        dispatch({
          type: 'page/refresh',
          payload: needLoading || false,
        });

        dispatch({
          type: 'page/setNeedRefreshOnShow',
          payload: { needRefreshOnShow: false, needLoading: false },
        });
      } else {
        if (cartReqNum !== 1) {
          //为什么要延迟50毫秒呢，因为购物车依赖 page/setBusinessType 修改state.businessType的值
          setTimeout(() => {
            $ele().utils.eventEmitter.emit('cartRequest', { restaurant_id: storeId });
          }, 50);
        }
      }

      dispatch({ type: 'page/pindanCheck' });

      // #ifndef miniapp
      if (platform.isEleme) {
        // 每次出现时候补偿一次,进native店铺可能会清理
        try {
          LMageX.addGlobalData({
            key: WEEX_SHOP_ENTER,
            value: 'true',
          });
        } catch (error) {}
      }
      // #endif
      setTimeout(() => {
        onShowExecutedRef.current = false;
      }, 500);
    }, [currentBusinessType, needRefreshOnShow, needLoading, storeId, dispatch]),
  );

  usePageOnHide(() => {
    // // // console.log('[first-screen-monitor] usePageOnHide');
    flushFirstScreenMonitor();
    // 页面隐藏时候补偿一个隐藏loading
    hideLoading();
  });

  // 事件初始化 - 页面可见性
  useInitPageVisibilityEvent();

  // 事件初始化 - 页面滚动
  useInitPageScrollEvent();

  // 适配无障碍改动，没问题后面删除 1016
  const disableFooterUIChange = window.__downgradedConfiguration?.disableFooterUIChange === 'true';

  return (
    <ErrorHandler onReload={reloadPage} key={errorHandlerKey}>
      {!disableFooterUIChange && <StoreFooter />}
      <ContentWrapper
        standard-sticky="true"
        nested-scroll="true"
        scroll-physics="clamping"
        className={classNames(styles.wrapperList, isWeex ? '' : 'isH5')}
        scrollbarWidth="none"
        msOverflowStyle="none"
        id="et-store-list"
        // scrollable={tabbarStickyState && isMenu ? 'false' : 'true'}
      >
        <ShopNav />
        {/* 新导航(sticky)会占位,需要负 marginTop 让店招铺到屏幕顶部、被 ShopNav 覆盖
            老导航(fixed)不占位,直接渲染 StoreHead 即可 */}
        {isNewShopNavEnabled() ? (
          (() => {
            let storeHeadMarginTop: string = '';
            // #ifdef miniapp
            storeHeadMarginTop = `${-getScreenInfo().statusBarHeight - 44}px`;
            // #endif
            // #ifndef miniapp
            storeHeadMarginTop = 'calc(-44px - var(--safe-area-inset-top, 44px))';
            // #endif
            return (
              <div style={{ marginTop: storeHeadMarginTop }}>
                <StoreHead />
              </div>
            );
          })()
        ) : (
          <StoreHead />
        )}
        <StoreStatus />
        <StoreHeadSpace />
        <StoreMemberCard></StoreMemberCard>
        <StoreTab />
        {/* 逻辑迁移到menu里 <StoreBody storeData={headData} loading={loading} /> */}
        <StoreSlider />
      </ContentWrapper>
      {disableFooterUIChange && <StoreFooter />}
      <ShopPromotionPopup />
      {showStoreBrandPopup && <StoreBrandPopup />}
      <StoreBookingPannel />
      {isDebugEnv() && <DebugIcon />}
      {showTimingRedenvelope && <TimingRedEnvelope />}
      {/* 帮你点组件 - 对应 Mist 中的 on-shop-carts-assistant 通知 */}
      {assistant?.show && platform.isEleme && storeId && (
        <HelpOrderEntry shopId={storeId} assistant={assistant} />
      )}
      <AlipayDynamicPopup></AlipayDynamicPopup>
    </ErrorHandler>
  );
};

export default () => {
  traceStart(['HOME_RENDER']);
  const urlParams = getUrlParams();

  // 直接同步获取缓存数据,开关在getHeadCacheWithSkeleton设置
  const cacheHead = urlParams?.shopId ? getHeadCacheWithSkeleton(urlParams?.shopId) : null;
  const cacheMenu = urlParams?.shopId ? getBodyCacheWithSkeleton(urlParams?.shopId) : null;
  // 从缓存数据中解析出需要的字段
  const cacheDataToken = cacheHead?.dataToken ?? 'empty';
  const cacheGlobalConfig = cacheHead?.extra?.globalConfig ?? {};
  const cacheStoreTheme = getThemeConfig(
    cacheGlobalConfig.theme ?? {},
    cacheGlobalConfig?.brandId,
    true,
  );
  const cacheStoreTabList =
    cacheHead?.data?.wm_store_header_tabbar?.fields?.items?.filter(
      (item: TabBarItem) => item.fields.type === '0' && item.fields.key !== 'newer_scene',
    ) ?? [];

  console.info(cacheMenu, cacheDataToken);

  // 定义初始状态，直接包含缓存数据和解析后的字段
  const initialState = {
    pageLoading: !(cacheHead || cacheMenu), // 有缓存就不显示loading
    urlParams,
    cart: null,
    cartsToShopPromotionParam: null,
    theme: 'light',
    storeTheme: cacheStoreTheme, // 使用缓存解析的主题
    message: 0,
    shopId: urlParams?.shopId,
    tbSellerId: null,
    tbStoreId: null,
    tabIndex: 0,
    menuIndex: 0,
    switchType: null,
    businessType: urlParams.businessType ?? '0',
    bookingData: null,
    headData: cacheHead, // 直接使用缓存数据
    menuData: cacheMenu, // 直接使用缓存数据
    sceneData: null, // 新人专享数据
    dataToken: cacheDataToken, // 使用缓存的 dataToken
    globalConfig: cacheGlobalConfig, // 使用缓存的全局配置
    storeTabList: cacheStoreTabList, // 使用缓存的 tab 列表
    showPromotionPopup: false, // 测试
    showBookingPannel: false, // 展示预订面板
    errorInstance: null,
    showSkyFallPopup: {},
    needRefreshOnShow: false,
    needLoading: false, // 新增：控制onShow时是否显示loading
    assistant: null, // 帮你点数据 - 对应 Mist 中的 assistant state
    menuAnchor: null,
    getMenuItem: null,
    showFooter: true,
    prefetchCheckout: {},
    abTest: {},
    tabbarStickyState: false, // tabbar 吸顶状态
    alipayDynamicPopupInfo: null,
    pindanEntrance: null, // 拼单入口数据
  };

  // 初始化时同步 URL 参数中的预约时间和 focusMustBuy 到 window.__GLOBAL_STATE__
  if (!window.__GLOBAL_STATE__) {
    window.__GLOBAL_STATE__ = {};
  }
  if (urlParams.bookTime || urlParams.deliveryTime) {
    window.__GLOBAL_STATE__.bookTime = urlParams.bookTime ?? '';
    window.__GLOBAL_STATE__.deliveryTime = urlParams.deliveryTime ?? '';
  }
  if (urlParams.focusMustBuy) {
    window.__GLOBAL_STATE__.focusMustBuy = urlParams.focusMustBuy === '1';
  }
  window.__GLOBAL_STATE__.menuFirstBuy = 1;
  return (
    <ETStoreProvider initialState={initialState}>
      <GlobalActionRegister />
      <Home />
    </ETStoreProvider>
  );
};

