73	  // 收藏弹框相关状态
74	  const [showCouponPopup, setShowCouponPopup] = useState(false);
75	  const [couponPopupInfo, setCouponPopupInfo] = useState<CouponPopupInfo | null>(null);
76	
77	  // Refs
78	  const rafRef = useRef<number>();
79	  const lastScrollTop = useRef(0);
80	  const isSearchExpanded = useRef(false);
81	
82	  const [tabTop] = useState(navBarHeight);
83	
84	  // 红包相关状态计算
85	  const redEnvelopeCountDownShow = useMemo(() => {
86	    if (!redEnvelope || redEnvelope.couponType !== 7) return false;
87	    if (!redEnvelope.countDown) return false;
88	    if (typeof redEnvelope.countDown !== 'number') return false;
89	    return redEnvelope.countDown < 60 * 60;
90	  }, [redEnvelope]);
91	
92	  const redEnvelopeWhiteButtonShow = useMemo(
93	    () => redEnvelopeCountDownShow,
94	    [redEnvelopeCountDownShow],
95	  );
96	
97	  // 透明度更新逻辑
98	  const updateOpacity = useCallback(
99	    (scrollTop: number) => {
100	      if (scrollTop < 0) {
101	        scrollTop = 0;
102	      }
103	      if (scrollTop > tabTop) {
104	        scrollTop = tabTop;
105	      }
106	      const scroll = scrollTop / tabTop;
107	      const rateNum = Number(scroll.toFixed(2));
108	      // 兜底透明度变化不及时
109	      const newOpacity = rateNum > 0.8 ? 1 : rateNum < 0.3 ? 0 : rateNum;
110	
111	      if (Math.abs(newOpacity - opacity) > 0.01) {
112	        setOpacity(newOpacity);
113	
114	        // 更新导航栏主题色
115	        if (newOpacity > 0.5) {
116	          $ele().utils.navbar.setTheme({ theme: 'LIGHT' });
117	        } else {
118	          $ele().utils.navbar.setTheme({ theme: 'DARK' });
119	        }
120	
121	        // 更新搜索栏的展开状态 - 关键：检查isSearchExpanded状态
122	        if (!isSearchExpanded.current) {
123	          setSearchExplandOpacity(newOpacity);
124	          setSearchIconOpacity(newOpacity);
125	
126	          // 根据红包按钮状态调整搜索框的移动距离
127	          const moveDistance = redEnvelopeWhiteButtonShow ? -44 : -72;
128	          setSearchTransform(newOpacity * moveDistance);
129	        }
130	      }
131	    },
132	    [tabTop, opacity, redEnvelopeWhiteButtonShow],
133	  );
134	
135	  // 滚动处理函数
136	  const handleScroll = useCallback(
137	    (e: any) => {
138	      if (rafRef.current) {
139	        cancelAnimationFrame(rafRef.current);
140	      }
141	
142	      // rafRef.current = requestAnimationFrame(() => {
143	      let scrollTop = 0;
144	
145	      // 优先从事件对象的 contentOffset.y 获取 scrollTop
146	      if (e?.detail?.contentOffset?.y !== undefined) {
147	        scrollTop = -e.detail.contentOffset.y;
148	      } else {
149	        // 降级方案：从 document 获取
150	        // @ts-ignore
151	        // eslint-disable-next-line no-restricted-properties
152	        // #ifdef miniapp
153	        scrollTop = e?.target?.scrollTop || 0;
154	        // #endif
155	        // #ifndef miniapp
156	        scrollTop = document.documentElement.scrollTop || 0;
157	        // #endif
158	      }
159	
160	      if (Math.abs(scrollTop - lastScrollTop.current) > 5) {
161	        lastScrollTop.current = scrollTop;
162	        updateOpacity(scrollTop);
163	      }
164	      notifyFirstScreenScrolled();
165	      // });
166	    },
167	    [updateOpacity],
168	  );
169	
170	  // 事件处理函数
171	  const onSearchClick = useMemo(
172	    () => createSearchClickHandler(search, globalConfig, navigateToShopSearch),
173	    [search, globalConfig, navigateToShopSearch],
174	  );
175	
176	  const handleCloseCouponPopup = useCallback(() => {
177	    setShowCouponPopup(false);
178	    setCouponPopupInfo(null);
179	  }, []);
180	
181	  const handleCouponPopupAddCart = useCallback(() => {
182	    // // // console.log('处理加购逻辑');
183	    // TODO: 实现加入购物车逻辑
184	    handleCloseCouponPopup();
185	  }, [handleCloseCouponPopup]);
186	
187	  const handleDefaultRedEnvelopeClick = useCallback(() => {
188	    $ele().ltracker.click('compositive_discount.1', {
189	      restaurant_id: globalConfig?.encryptStoreId,
190	      type: redEnvelope?.text && redEnvelope?.text?.length > 0 ? 2 : 1,
191	    });
192	    dispatch({ type: 'page/setShowPromotionPopup', payload: true });
193	  }, [dispatch, globalConfig?.encryptStoreId, redEnvelope?.text]);
194	
195	  const handleScrollRedEnvelopeClick = useCallback(() => {
196	    if (opacity < 0.1) {
197	      $ele().ltracker.click('search.1', search?.userTrack?.bizParams ?? {});
198	      onSearchClick('icon');
199	      return;
200	    }
201	    $ele().ltracker.click('compositive_discount.1', {
202	      restaurant_id: globalConfig?.encryptStoreId,
203	      type: redEnvelope?.text && redEnvelope?.text?.length > 0 ? 2 : 1,
204	    });
205	    dispatch({ type: 'page/setShowPromotionPopup', payload: true });
206	  }, [
207	    opacity,
208	    onSearchClick,
209	    dispatch,
210	    globalConfig?.encryptStoreId,
211	    redEnvelope?.text,
212	    search?.userTrack,
213	  ]);
214	
215	  // 返回处理函数(所有环境统一)
216	  const onBack = useCallback(() => {
217	    // #ifdef miniapp
218	    my?.navigateBack();
219	    // #endif
220	    // #ifndef miniapp
221	    Navigator.close({});
222	    // #endif
223	  }, []);
224	
225	  // 计算 transitionHeight (店招高度 - 导航栏高度)
226	  useEffect(() => {
227	    const html = document.documentElement;
228	    const clientWidth = Math.round(html.clientWidth || window.innerWidth);
229	    // 店铺店招高度约为 38.4vw (标准) 或 56vw (high style)
230	    const posterHeight = isHighStyle ? 56 * clientWidth / 100 : 38.4 * clientWidth / 100;
231	    const navHeight = statusBarHeight + 44;
232	    setTransitionHeight(Math.max(0, posterHeight - navHeight));
233	  }, [isHighStyle, statusBarHeight]);
234	
235	  // 初始化效果
236	  useEffect(() => {
237	    // $ele().utils.navbar.setImmersive({ immersive: true });
238	    // $ele().utils.navbar.setTheme({ theme: 'DARK' });
239	  }, []);
240	
241	  useEffect(() => {
242	    const handler = () => {
243	      updateOpacity(tabTop);
244	    };
245	    $ele().utils.eventEmitter.on('menuWillAnchor', handler);
246	    return () => {
247	      $ele().utils.eventEmitter.off('menuWillAnchor', handler);
248	    };
249	  }, [tabTop, updateOpacity]);
250	
251	  useEffect(() => {
252	    setOpacity(isSingleShop ? 1 : 0);
253	    setSearchExplandOpacity(isSingleShop ? 1 : 0);
254	    setSearchIconOpacity(isSingleShop ? 1 : 0);
255	  }, [isSingleShop]);
256	
257	  // 监听滚动事件
258	  useEffect(() => {
259	    // 极简店铺不监听滚动事件
260	    if (isSingleShop) {
261	      // setTheme 内部已处理预热逻辑
262	      $ele().utils.navbar.setTheme({ theme: 'LIGHT' });
263	      return;
264	    }
265	    // @ts-ignore
266	    // eslint-disable-next-line no-restricted-properties
267	    const $list = document.getElementById('et-store-list');
268	    let useComponentListener = $ele().utils.platform.isEA || $ele().utils.isWeex;
269	    console.log('[ShopNav] useComponentListener', useComponentListener);
270	    if ($list && useComponentListener) {
271	      $list.addEventListener('scroll', handleScroll);
272	    } else {
273	      // @ts-ignore
274	      window.addEventListener('scroll', handleScroll, { passive: true });
275	    }
276	
277	    return () => {
278	      // @ts-ignore
279	      if ($list && useComponentListener) {
280	        $list.removeEventListener('scroll', handleScroll);
281	      } else {
282	        // @ts-ignore
283	        window.removeEventListener('scroll', handleScroll);
284	      }
285	      if (rafRef.current) {
286	        cancelAnimationFrame(rafRef.current);
287	      }
288	    };
289	  }, [handleScroll, isSingleShop]);
290	
291	  useEffect(() => {
292	    // 初始化导航栏颜色
293	    // 更新导航栏主题色
294	    if (opacity > 0.5) {
295	      $ele().utils.navbar.setTheme({ theme: 'LIGHT' });
296	    } else {
297	      $ele().utils.navbar.setTheme({ theme: 'DARK' });
298	    }
299	  }, []);
300	
301	  // 如果没有有效数据，不显示组件
302	  if (!fields) {
303	    return null;
304	  }
305	
306	  const hasDeliveryBusiness = shouldShowNavbarDeliveryBusiness(deliveryBusinessInfo);
307	
308	  return (
309	    <>
310	      <Navigation
311	        mode={opacity > 0.5 ? 'light' : 'dark'}
312	        title={
313	          <div style={{ display: 'flex', alignItems: 'center', width: '100%', height: '44px', overflow: 'visible' }}>
314	            {/* DeliveryBusinessNavbar: 始终显示在左侧 */}
315	            {hasDeliveryBusiness && (
316	              <div style={{ marginRight: 'auto' }}>
317	                <DeliveryBusinessNavbar
318	                  deliveryBusinessInfo={deliveryBusinessInfo ?? undefined}
319	                  currentBusinessType={deliveryBusinessInfo?.businessType}
320	                  onBusinessTypeChange={(businessType) => {
321	                    // TODO: 实现业务类型切换逻辑
322	                  }}
323	                  isVisible={true}
324	                  opacity={calculateNavbarDeliveryOpacity(deliveryBusinessInfo, opacity)}
325	                  backgroundType={opacity > 0.5 ? 'gray' : 'transparent'}
326	                />
327	              </div>
328	            )}
329	            
330	            {/* 右侧按钮组 */}
331	            <div style={{ display: 'flex', alignItems: 'center', marginLeft: hasDeliveryBusiness ? '0' : 'auto' }}>
332	              {/* 搜索区域 */}
333	              {search && (
334	                <SearchSection
335	                  search={search}
336	                  storeDecoType={storeDecoType}
337	                  searchExplandOpacity={searchExplandOpacity}
338	                  searchIconOpacity={searchIconOpacity}
339	                  searchTransform={searchTransform}
340	                  redEnvelope={redEnvelope}
341	                  redEnvelopeWhiteButtonShow={redEnvelopeWhiteButtonShow}
342	                  hasDeliveryBusiness={hasDeliveryBusiness}
343	                  opacity={opacity}
344	                  onSearchClick={onSearchClick}
345	                />
346	              )}
347	
348	              {/* 红包区域 */}
349	              {redEnvelope && (
350	                <RedEnvelopeSection
351	                  redEnvelope={redEnvelope}
352	                  opacity={opacity}
353	                  searchExplandOpacity={searchExplandOpacity}
354	                  redEnvelopeCountDownShow={redEnvelopeCountDownShow}
355	                  redEnvelopeWhiteButtonShow={redEnvelopeWhiteButtonShow}
356	                  onDefaultClick={handleDefaultRedEnvelopeClick}
357	                  onScrollClick={handleScrollRedEnvelopeClick}
358	                />
359	              )}
360	
361	              {/* IM 客服区域 */}
362	              {showIM && storeIm && (
363	                <ImSection storeIm={storeIm} opacity={opacity} storeDecoType={storeDecoType} />
364	              )}
365	
366	              {/* 收藏区域 */}
367	              {favored && (
368	                <FavoriteSection
369	                  favored={favored}
370	                  opacity={opacity}
371	                  storeDecoType={storeDecoType}
372	                  redEnvelope={redEnvelope}
373	                  redEnvelopeCountDownShow={redEnvelopeCountDownShow}
374	                  shopId={globalConfig?.encryptStoreId}
375	                  setShowCouponPopup={setShowCouponPopup}
376	                  setCouponPopupInfo={setCouponPopupInfo}
377	                />
378	              )}
379	            </div>
380	          </div>
381	        }
382	        onClickBack={onBack}
383	        // #ifdef miniapp
384	        style={{
385	          padding: `${statusBarHeight}px 10px 0`,
386	          height: `${statusBarHeight + 44}px`,
387	        }}
388	        // #endif
389	        transitionConfig={{
390	          open: true,
391	          targetColor: '#ffffff',
392	          targetMode: 'light',
393	          transitionHeight: transitionHeight,
394	        }}
395	      />
396	
397	      {/* 收藏弹框 */}
398	      <CouponPopup
399	        visible={showCouponPopup}
400	        couponPopupInfo={couponPopupInfo}
401	        onClose={handleCloseCouponPopup}
402	        onAddCart={handleCouponPopupAddCart}
403	      />
404	    </>
405	  );
406	};
407	export default ShopNav;
408

